// Hashi (Bridges) logic utilities.
// Bridges are stored as Map<string, number> where key is "x1,y1,x2,y2" in grid units,
// canonicalized so the smaller endpoint (x then y) comes first.

export const ERRORS = {
  NON_ADJ: 'Cannot connect non-adjacent islands',
  MAX_PAIR: 'Max 2 bridges per pair',
  EXCEED: 'Island would exceed its number',
  CROSS: 'Bridges would cross'
};

export function canonicalKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const first = (a.x < b.x) || (a.x === b.x && a.y < b.y) ? a : b;
  const second = first === a ? b : a;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

export function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

export function isAligned(from, to) {
  return from.x === to.x || from.y === to.y;
}

export function islandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

export function areAdjacent(islands, from, to) {
  if (!isAligned(from, to)) return false;
  const dx = Math.sign(to.x - from.x);
  const dy = Math.sign(to.y - from.y);
  let x = from.x + dx;
  let y = from.y + dy;
  while (x !== to.x || y !== to.y) {
    if (islandAt(islands, x, y)) return false;
    x += dx;
    y += dy;
  }
  return true;
}

function segmentsCross(segA, segB) {
  // seg: {x1,y1,x2,y2} aligned axis.
  const aVert = segA.x1 === segA.x2;
  const bVert = segB.x1 === segB.x2;

  // Parallel segments cannot "cross" in Hashi sense (overlap). We only treat perpendicular intersections.
  if (aVert === bVert) return false;

  const v = aVert ? segA : segB;
  const h = aVert ? segB : segA;

  const vx = v.x1;
  const vyMin = Math.min(v.y1, v.y2);
  const vyMax = Math.max(v.y1, v.y2);

  const hy = h.y1;
  const hxMin = Math.min(h.x1, h.x2);
  const hxMax = Math.max(h.x1, h.x2);

  const intersects = (vx > hxMin && vx < hxMax && hy > vyMin && hy < vyMax);
  return intersects;
}

export function bridgesWouldCross(bridges, newSegKey) {
  const newSeg = parseKey(newSegKey);
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    if (key === newSegKey) continue;
    const seg = parseKey(key);
    if (segmentsCross(newSeg, seg)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map(islands.map((i) => [i.id, 0]));
  // index by coordinate to island id
  const posToId = new Map(islands.map((i) => [`${i.x},${i.y}`, i.id]));

  for (const [key, num] of bridges.entries()) {
    if (!num) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const id1 = posToId.get(`${x1},${y1}`);
    const id2 = posToId.get(`${x2},${y2}`);
    if (!id1 || !id2) continue;
    counts.set(id1, (counts.get(id1) || 0) + num);
    counts.set(id2, (counts.get(id2) || 0) + num);
  }
  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  // delta is +1 (add) or -1 (remove). For UI we mostly validate +1.
  if (!from || !to) return { valid: false, error: ERRORS.NON_ADJ };
  if (from.id === to.id) return { valid: false, error: ERRORS.NON_ADJ };
  if (!areAdjacent(islands, from, to)) return { valid: false, error: ERRORS.NON_ADJ };

  const key = canonicalKey(from, to);
  const cur = bridges.get(key) || 0;
  const next = cur + delta;

  if (next > 2) return { valid: false, error: ERRORS.MAX_PAIR };
  if (next < 0) return { valid: false, error: null };

  if (delta > 0) {
    const counts = computeCurrentCounts(islands, bridges);
    const fromCount = counts.get(from.id) || 0;
    const toCount = counts.get(to.id) || 0;
    if (fromCount + 1 > from.value || toCount + 1 > to.value) {
      return { valid: false, error: ERRORS.EXCEED };
    }

    // crossing check only for actual segment existence (next>0)
    const test = new Map(bridges);
    test.set(key, next);
    if (bridgesWouldCross(test, key)) {
      return { valid: false, error: ERRORS.CROSS };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;
  const posToId = new Map(islands.map((i) => [`${i.x},${i.y}`, i.id]));
  const adj = new Map(islands.map((i) => [i.id, new Set()]));

  for (const [key, num] of bridges.entries()) {
    if (!num) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = posToId.get(`${x1},${y1}`);
    const b = posToId.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a).add(b);
    adj.get(b).add(a);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const q = [start];
  while (q.length) {
    const u = q.shift();
    for (const v of adj.get(u) || []) {
      if (!seen.has(v)) {
        seen.add(v);
        q.push(v);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // no crossing
  for (const [key, num] of bridges.entries()) {
    if (!num) continue;
    if (bridgesWouldCross(bridges, key)) return false;
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const i of islands) {
    if ((counts.get(i.id) || 0) !== i.value) return false;
  }

  return checkConnectivity(islands, bridges);
}
