import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PUZZLES } from './data/puzzles.js';
import {
  canonicalKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
  parseKey,
  ERRORS
} from './utils/hashiLogic.js';

const GRID = 40;
const W = 800;
const H = 600;

function px(n) {
  return n * GRID;
}

function getNeighborInDirection(islands, from, dir) {
  // dir: 'left'|'right'|'up'|'down'
  const candidates = islands.filter((i) => i.id !== from.id);
  let best = null;
  let bestDist = Infinity;

  for (const t of candidates) {
    if (dir === 'left' && t.y === from.y && t.x < from.x) {
      const d = from.x - t.x;
      if (d < bestDist) {
        bestDist = d;
        best = t;
      }
    }
    if (dir === 'right' && t.y === from.y && t.x > from.x) {
      const d = t.x - from.x;
      if (d < bestDist) {
        bestDist = d;
        best = t;
      }
    }
    if (dir === 'up' && t.x === from.x && t.y < from.y) {
      const d = from.y - t.y;
      if (d < bestDist) {
        bestDist = d;
        best = t;
      }
    }
    if (dir === 'down' && t.x === from.x && t.y > from.y) {
      const d = t.y - from.y;
      if (d < bestDist) {
        bestDist = d;
        best = t;
      }
    }
  }
  return best;
}

function lineMidpoint(from, to) {
  return { x: (from.x + to.x) / 2, y: (from.y + to.y) / 2 };
}

export default function App() {
  const [puzzleId, setPuzzleId] = useState(PUZZLES[0].id);
  const puzzle = useMemo(() => PUZZLES.find((p) => p.id === puzzleId) || PUZZLES[0], [puzzleId]);

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(() => puzzle.islands[0]?.id ?? null);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  useEffect(() => {
    // On puzzle change: fully reset state.
    setBridges(new Map());
    setSelectedIslandId(null);
    setCursorIslandId(puzzle.islands[0]?.id ?? null);
    setError(null);
  }, [puzzleId]);

  const islands = puzzle.islands;
  const islandById = useMemo(() => new Map(islands.map((i) => [i.id, i])), [islands]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValid(valid) {
    if (valid) setError(null);
  }

  function applyCycleBridge(from, to) {
    // cycle: 0 -> 1 -> 2 -> 0
    const key = canonicalKey(from, to);
    const cur = bridges.get(key) || 0;
    const target = (cur + 1) % 3;

    if (target > cur) {
      // validate +1 step(s)
      let temp = new Map(bridges);
      let c = cur;
      while (c < target) {
        const check = canAddBridge(islands, temp, from, to, +1);
        if (!check.valid) {
          setError(check.error);
          return;
        }
        c += 1;
        temp.set(key, c);
      }
      setBridges(temp);
      clearErrorOnValid(true);
      return;
    }

    // going to 0: always allowed
    const next = new Map(bridges);
    if (target === 0) next.delete(key);
    else next.set(key, target);
    setBridges(next);
    clearErrorOnValid(true);
  }

  function toggleBridge(from, to) {
    // toggle for right-click/ctrl-click: 0 <-> 1
    const key = canonicalKey(from, to);
    const cur = bridges.get(key) || 0;
    if (cur === 0) {
      const check = canAddBridge(islands, bridges, from, to, +1);
      if (!check.valid) {
        setError(check.error);
        return;
      }
      const next = new Map(bridges);
      next.set(key, 1);
      setBridges(next);
      clearErrorOnValid(true);
    } else {
      const next = new Map(bridges);
      next.delete(key);
      setBridges(next);
      clearErrorOnValid(true);
    }
  }

  function onIslandClick(island, evt) {
    evt.preventDefault();
    setCursorIslandId(island.id);

    if (!selectedIslandId) {
      setSelectedIslandId(island.id);
      return;
    }

    if (selectedIslandId === island.id) {
      // clicking same island: keep it selected
      return;
    }

    const from = islandById.get(selectedIslandId);
    const to = island;
    applyCycleBridge(from, to);
    setSelectedIslandId(to.id); // second click becomes new selection anchor
  }

  function onBackgroundClick() {
    setSelectedIslandId(null);
  }

  function onBridgeContextMenu(from, to, evt) {
    evt.preventDefault();
    toggleBridge(from, to);
  }

  function onBridgeClick(from, to, evt) {
    if (evt.ctrlKey) {
      evt.preventDefault();
      toggleBridge(from, to);
    }
  }

  useEffect(() => {
    function handleKeyDown(e) {
      const cursor = cursorIslandId ? islandById.get(cursorIslandId) : null;
      if (!cursor) return;

      if (e.key === 'Escape') {
        setSelectedIslandId(null);
        return;
      }

      if (e.key === 'Enter') {
        if (!selectedIslandId) {
          setSelectedIslandId(cursor.id);
        } else {
          const from = islandById.get(selectedIslandId);
          const to = cursor;
          if (from && to && from.id !== to.id) {
            applyCycleBridge(from, to);
            setSelectedIslandId(to.id);
          }
        }
        return;
      }

      const dirMap = {
        ArrowLeft: 'left',
        ArrowRight: 'right',
        ArrowUp: 'up',
        ArrowDown: 'down'
      };
      const dir = dirMap[e.key];
      if (!dir) return;
      e.preventDefault();

      const n = getNeighborInDirection(islands, cursor, dir);
      if (n) setCursorIslandId(n.id);
    }

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIslandId, islandById, islands, selectedIslandId, bridges]);

  const bridgeSegments = useMemo(() => {
    const segs = [];
    for (const [key, num] of bridges.entries()) {
      if (!num) continue;
      const { x1, y1, x2, y2 } = parseKey(key);
      const from = islands.find((i) => i.x === x1 && i.y === y1);
      const to = islands.find((i) => i.x === x2 && i.y === y2);
      if (!from || !to) continue;
      segs.push({ key, from, to, num });
    }
    return segs;
  }, [bridges, islands]);

  return (
    <div className="app">
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleId}
            onChange={(e) => setPuzzleId(e.target.value)}
            aria-label="Puzzle selector"
          >
            {PUZZLES.map((p) => (
              <option key={p.id} value={p.id}>{p.label}</option>
            ))}
          </select>
        </label>

        <button
          onClick={() => {
            setBridges(new Map());
            setSelectedIslandId(null);
            setError(null);
          }}
        >
          Reset
        </button>

        <div style={{ opacity: 0.85 }}>
          Use mouse or keyboard (arrows/Enter/Esc). Ctrl+click/right-click bridge toggles.
        </div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        className="board"
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
        onMouseDown={(e) => {
          // if clicking on empty SVG
          if (e.target === svgRef.current) onBackgroundClick();
        }}
      >
        {/* Bridges */}
        <g stroke="#00ff66" strokeLinecap="round">
          {bridgeSegments.map(({ key, from, to, num }) => {
            const x1 = px(from.x);
            const y1 = px(from.y);
            const x2 = px(to.x);
            const y2 = px(to.y);
            const isH = y1 === y2;
            const offset = 6;

            const lines = [];
            const commonProps = {
              key: key,
              onContextMenu: (evt) => onBridgeContextMenu(from, to, evt),
              onClick: (evt) => onBridgeClick(from, to, evt),
              style: { cursor: 'pointer' }
            };

            if (num === 1) {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-1`}
                  x1={x1}
                  y1={y1}
                  x2={x2}
                  y2={y2}
                  strokeWidth={4}
                />
              );
            } else if (num === 2) {
              if (isH) {
                lines.push(
                  <line
                    {...commonProps}
                    key={`${key}-a`}
                    x1={x1}
                    y1={y1 - offset}
                    x2={x2}
                    y2={y2 - offset}
                    strokeWidth={4}
                  />,
                  <line
                    {...commonProps}
                    key={`${key}-b`}
                    x1={x1}
                    y1={y1 + offset}
                    x2={x2}
                    y2={y2 + offset}
                    strokeWidth={4}
                  />
                );
              } else {
                lines.push(
                  <line
                    {...commonProps}
                    key={`${key}-a`}
                    x1={x1 - offset}
                    y1={y1}
                    x2={x2 - offset}
                    y2={y2}
                    strokeWidth={4}
                  />,
                  <line
                    {...commonProps}
                    key={`${key}-b`}
                    x1={x1 + offset}
                    y1={y1}
                    x2={x2 + offset}
                    y2={y2}
                    strokeWidth={4}
                  />
                );
              }
            }

            return <g key={key}>{lines}</g>;
          })}
        </g>

        {/* Keyboard cursor (not a circle) */}
        {cursorIslandId && islandById.get(cursorIslandId) ? (() => {
          const c = islandById.get(cursorIslandId);
          const cx = px(c.x);
          const cy = px(c.y);
          const size = 34;
          return (
            <g>
              <rect
                x={cx - size / 2}
                y={cy - size / 2}
                width={size}
                height={size}
                fill="none"
                stroke="#00ff66"
                strokeWidth={2}
                strokeDasharray="6 4"
                opacity={0.9}
              />
            </g>
          );
        })() : null}

        {/* Islands */}
        <g>
          {islands.map((i) => {
            const cx = px(i.x);
            const cy = px(i.y);
            const isSelected = selectedIslandId === i.id;
            const curCount = counts.get(i.id) || 0;
            const satisfied = curCount === i.value;
            const over = curCount > i.value;

            return (
              <g key={i.id} onClick={(evt) => onIslandClick(i, evt)} style={{ cursor: 'pointer' }}>
                <circle
                  cx={cx}
                  cy={cy}
                  r={16}
                  fill="#000"
                  stroke={over ? '#ff3355' : (isSelected ? '#00ff66' : 'rgba(0,255,102,0.7)')}
                  strokeWidth={isSelected ? 3 : 2}
                />
                <text
                  x={cx}
                  y={cy + 5}
                  textAnchor="middle"
                  fontSize="16"
                  fill={satisfied ? '#00ff66' : 'rgba(0,255,102,0.9)'}
                >
                  {i.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </div>
  );
}
